INSERT INTO `aowow_guides` VALUES (1,3,0,-1,'Lunar Festival','Lunar Festival','It\'s time for the Lunar Festival, so everyone break out the fireworks, show a little respect for your elders, and come celebrate the (lunar) new year!','lunar-festival',0,3,1,769,0,0,0,1640991600,0,1647901298,NULL,0),(2,3,0,-1,'Noblegarden','Noblegarden','It\'s time for Noblegarden, and yet another hunt for phat loot in World of Warcraft, this time in the form of brightly colored eggs!','noblegarden',0,3,1,769,0,0,0,1640991600,0,1647901298,NULL,0),(3,3,0,-1,'Love is in the Air','Love is in the Air','Ah, love is in the air in the World of Warcraft: sweet flowers, perfume, and sharing gifts with loved ones!','love-is-in-the-air',0,3,1,769,0,0,0,1640991600,0,1647901298,NULL,0),(4,3,0,-1,'Childrens Week','Childrens Week','Children\'s Week is a week in which we brave face a challenge greater than any undead monstrosity, a task more daunting than saving the world. We must become parents.','childrens-week',0,3,1,769,0,0,0,1640991600,0,1647901298,NULL,0),(5,3,0,-1,'Midsummer Fire Festival','Midsummer Fire Festival','Midsummer is here! There are bonfires located in each major capital city (and throughout the world), which are surrounded by questgivers and merchants.','midsummer-fire-festival',0,3,1,769,0,0,0,1640991600,0,1647901298,NULL,0),(6,3,0,-1,'Brewfest','Brewfest','Quests completed during Brewfest will award Brewfest Prize Token which can be redeemed for items by speaking to either Blix Fixwidget or Belbi Quikswitch.','brewfest',0,3,1,769,0,0,0,1640991600,0,1647901298,NULL,0),(7,3,0,-1,'Hallow\'s End','Hallow\'s End','It\'s that time again folks-time to dress up in a ridiculous costume, and go score some treats!  It\'s Hallow\'s End!','hallows-end',0,3,1,769,0,0,0,1640991600,0,1647901298,NULL,0),(8,3,0,-1,'Pilgrim\'s Bounty','Pilgrim\'s Bounty','It\'s time to reflect on your journeys and good fortune, share plentiful food, and stories with friends.','pilgrims-bounty',0,3,1,769,0,0,0,1640991600,0,1647901298,NULL,0),(9,3,0,-1,'Feast of Winter Veil','Feast of Winter Veil','Deck the halls with boughs of Preserved Holly, and have a merry Winter Veil! Cheers!','winter-veil',0,3,1,769,0,0,0,1640991600,0,1647901298,NULL,0);
